-- ============================================================================\n-- PostgreSQL Initialization Script\n-- Database schemas for Lakehouse metadata, Airflow, and Glue Catalog\n-- ============================================================================\n\n-- ============================================================================\n-- AIRFLOW SCHEMA (created by Airflow automatically on first run)\n-- ============================================================================\n-- This will be auto-generated, but we ensure the DB exists\nCREATE DATABASE IF NOT EXISTS airflow;\nGRANT ALL PRIVILEGES ON DATABASE airflow TO airflow;\n\n-- ============================================================================\n-- LAKEHOUSE METADATA SCHEMA\n-- ============================================================================\nCREATE SCHEMA IF NOT EXISTS lakehouse_metadata\n    AUTHORIZATION airflow;\n\nCOMMENT ON SCHEMA lakehouse_metadata IS 'Lakehouse metadata and lineage tracking';\n\n-- Data lineage table\nCREATE TABLE IF NOT EXISTS lakehouse_metadata.data_lineage (\n    id SERIAL PRIMARY KEY,\n    source_table VARCHAR(255) NOT NULL,\n    target_table VARCHAR(255) NOT NULL,\n    transformation_job VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    CONSTRAINT lineage_unique UNIQUE(source_table, target_table, transformation_job)\n);\n\nCREATE INDEX idx_lineage_source ON lakehouse_metadata.data_lineage(source_table);\nCREATE INDEX idx_lineage_target ON lakehouse_metadata.data_lineage(target_table);\nCREATE INDEX idx_lineage_job ON lakehouse_metadata.data_lineage(transformation_job);\n\nCOMMENT ON TABLE lakehouse_metadata.data_lineage IS 'Tracks data transformations and dependencies';\n\n-- Data quality checks\nCREATE TABLE IF NOT EXISTS lakehouse_metadata.data_quality_checks (\n    id SERIAL PRIMARY KEY,\n    table_name VARCHAR(255) NOT NULL,\n    check_type VARCHAR(50) NOT NULL,  -- 'completeness', 'uniqueness', 'validity'\n    check_name VARCHAR(255) NOT NULL,\n    passed BOOLEAN NOT NULL,\n    total_rows BIGINT,\n    failed_rows BIGINT,\n    check_timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    CONSTRAINT quality_check_unique UNIQUE(table_name, check_name, check_timestamp)\n);\n\nCREATE INDEX idx_quality_table ON lakehouse_metadata.data_quality_checks(table_name);\nCREATE INDEX idx_quality_timestamp ON lakehouse_metadata.data_quality_checks(check_timestamp);\n\nCOMMENT ON TABLE lakehouse_metadata.data_quality_checks IS 'Data quality validation results';\n\n-- Pipeline execution logs\nCREATE TABLE IF NOT EXISTS lakehouse_metadata.pipeline_executions (\n    id SERIAL PRIMARY KEY,\n    pipeline_name VARCHAR(255) NOT NULL,\n    start_time TIMESTAMP NOT NULL,\n    end_time TIMESTAMP,\n    status VARCHAR(20) NOT NULL,  -- 'RUNNING', 'SUCCESS', 'FAILED'\n    error_message TEXT,\n    rows_processed BIGINT,\n    data_volume_mb FLOAT,\n    execution_duration_seconds INT,\n    CONSTRAINT execution_unique UNIQUE(pipeline_name, start_time)\n);\n\nCREATE INDEX idx_execution_pipeline ON lakehouse_metadata.pipeline_executions(pipeline_name);\nCREATE INDEX idx_execution_status ON lakehouse_metadata.pipeline_executions(status);\nCREATE INDEX idx_execution_start ON lakehouse_metadata.pipeline_executions(start_time);\n\nCOMMENT ON TABLE lakehouse_metadata.pipeline_executions IS 'ETL pipeline execution history and telemetry';\n\n-- ============================================================================\n-- AWS GLUE CATALOG MIRROR (optional, for local reference)\n-- ============================================================================\nCREATE SCHEMA IF NOT EXISTS glue_catalog\n    AUTHORIZATION airflow;\n\nCOMMENT ON SCHEMA glue_catalog IS 'Mirror of AWS Glue Data Catalog metadata';\n\nCREATE TABLE IF NOT EXISTS glue_catalog.databases (\n    database_name VARCHAR(255) PRIMARY KEY,\n    description TEXT,\n    location VARCHAR(1024),\n    parameters TEXT,  -- JSON\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS glue_catalog.tables (\n    database_name VARCHAR(255) NOT NULL,\n    table_name VARCHAR(255) NOT NULL,\n    s3_location VARCHAR(1024),\n    input_format VARCHAR(255),\n    output_format VARCHAR(255),\n    serde_info VARCHAR(255),\n    columns TEXT,  -- JSON array\n    partition_keys TEXT,  -- JSON array\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    PRIMARY KEY(database_name, table_name),\n    FOREIGN KEY(database_name) REFERENCES glue_catalog.databases(database_name)\n);\n\nCREATE INDEX idx_glue_table_location ON glue_catalog.tables(s3_location);\n\n-- ============================================================================\n-- PERMISSIONS\n-- ============================================================================\nGRANT USAGE ON SCHEMA lakehouse_metadata TO airflow;\nGRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA lakehouse_metadata TO airflow;\nGRANT USAGE ON SCHEMA glue_catalog TO airflow;\nGRANT SELECT, INSERT, UPDATE ON ALL TABLES IN SCHEMA glue_catalog TO airflow;\n\n-- ============================================================================\n-- FUNCTIONS & TRIGGERS\n-- ============================================================================\n\n-- Auto-update updated_at timestamp\nCREATE OR REPLACE FUNCTION update_updated_at_column()\nRETURNS TRIGGER AS $$\nBEGIN\n    NEW.updated_at = CURRENT_TIMESTAMP;\n    RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER update_lineage_timestamp BEFORE UPDATE ON lakehouse_metadata.data_lineage\n    FOR EACH ROW\n    EXECUTE FUNCTION update_updated_at_column();\n\nCREATE TRIGGER update_catalog_tables_timestamp BEFORE UPDATE ON glue_catalog.tables\n    FOR EACH ROW\n    EXECUTE FUNCTION update_updated_at_column();\n\n-- ============================================================================\n-- SAMPLE DATA FOR TESTING\n-- ============================================================================\nINSERT INTO glue_catalog.databases (database_name, description, location)\nVALUES \n    ('lakehouse_assurance_moto_catalog', 'Main lakehouse database for assurance moto', 's3://lakehouse-assurance-moto-dev/')\nON CONFLICT (database_name) DO NOTHING;\n\nINSERT INTO glue_catalog.tables (database_name, table_name, s3_location, input_format, output_format, serde_info)\nVALUES\n    ('lakehouse_assurance_moto_catalog', 'bronze_client', 's3://lakehouse-assurance-moto-dev/bronze/Client/', 'org.apache.hadoop.mapred.TextInputFormat', 'org.apache.hadoop.hive.ql.io.HiveIgnoreKeyTextOutputFormat', 'org.apache.hadoop.hive.serde2.lazy.LazySimpleSerDe'),\n    ('lakehouse_assurance_moto_catalog', 'bronze_contrat1', 's3://lakehouse-assurance-moto-dev/bronze/contrat1/', 'org.apache.hadoop.mapred.TextInputFormat', 'org.apache.hadoop.hive.ql.io.HiveIgnoreKeyTextOutputFormat', 'org.apache.hadoop.hive.serde2.lazy.LazySimpleSerDe'),\n    ('lakehouse_assurance_moto_catalog', 'bronze_contrat2', 's3://lakehouse-assurance-moto-dev/bronze/Contrat2/', 'org.apache.hadoop.mapred.TextInputFormat', 'org.apache.hadoop.hive.ql.io.HiveIgnoreKeyTextOutputFormat', 'org.apache.hadoop.hive.serde2.lazy.LazySimpleSerDe'),\n    ('lakehouse_assurance_moto_catalog', 'silver_client_contrat', 's3://lakehouse-assurance-moto-dev/silver/Client_contrat_silver/', 'org.apache.hadoop.mapred.TextInputFormat', 'org.apache.hadoop.hive.ql.io.HiveIgnoreKeyTextOutputFormat', 'org.apache.hadoop.hive.serde2.lazy.LazySimpleSerDe')\nON CONFLICT (database_name, table_name) DO NOTHING;\n\nCOMMIT;\n